{
  "name": "gemini-custom-tools",
  "version": "1.0.0",
  "description": "Custom tools for Gemini CLI",
  "type": "module",
  "scripts": {
    "build": "tsc",
    "start": "node dist/gemini-history.js"
  },
  "dependencies": {
    "@google/gemini-cli-core": "file:../packages/core",
    "@google/genai": "^1.40.0"
  },
  "devDependencies": {
    "@types/node": "^25.2.0",
    "typescript": "^5.9.3"
  }
}

{
  "compilerOptions": {
    "target": "ES2022",
    "module": "NodeNext",
    "moduleResolution": "NodeNext",
    "outDir": "./dist",
    "strict": true,
    "esModuleInterop": true,
    "skipLibCheck": true,
    "forceConsistentCasingInFileNames": true,
    "allowJs": true,
    "resolveJsonModule": true,
    "paths": {
      "@google/gemini-cli-core/*": ["../packages/core/*"]
    }
  },
  "include": ["src/**/*"]
}

