        rawOutput += `## Session: Unknown\n\n`;
      }

      if (insight.tools && insight.tools.length > 0) {
        rawOutput += "```json\n";
        rawOutput += JSON.stringify(insight.tools, null, 2);
        rawOutput += "\n```\n\n";
      } else {
        rawOutput += "_No tools detected._\n\n";
      }
      rawOutput += "---\n\n";
    }
