export async function processLogFileWithRetry<T>(
  filePath: string,
  processFunction: (filePath: string) => Promise<BaseProcessResult<T> | null>,
  maxRetriesPerRequest: number = MAX_RETRIES_PER_REQUEST,
  maxTotalRetries: number = MAX_TOTAL_RETRIES
