  private emitQuotaChangedEvent(): void {
    const pooled = this.getPooledQuota();
    if (
      this.lastEmittedQuotaRemaining !== pooled.remaining ||
      this.lastEmittedQuotaLimit !== pooled.limit
    ) {
      this.lastEmittedQuotaRemaining = pooled.remaining;
      this.lastEmittedQuotaLimit = pooled.limit;
      coreEvents.emitQuotaChanged(
        pooled.remaining,
        pooled.limit,
        pooled.resetTime,
      );
    }
  }

